var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"어? 이게 뭐지?","JPN":"あれ？　なんだこれ？","ENG":"Huh? What is this?","TWN":"嗯？這是什麼？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>에블린의 연구일지</color>?","JPN":"<color=#ffd34c>エヴリンの研究日誌</color>?","ENG":"<color=#ffd34c>Evelyn’s Research Notes</color>?","TWN":"<color=#ffd34c>伊芙琳的研究日記</color>？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이거 에블린이 맨날 들고 다니던 거잖아?","JPN":"これはエヴリンが毎日持ち歩いてたものだよね？","ENG":"These are the notes that Evelyn always carries around.","TWN":"這不是伊芙琳每天都帶在身邊的嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"얼른 가져다 줘야지~","JPN":"早く持って行ってあげないと！","ENG":"I’m taking this back to her.","TWN":"要趕快還給她～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"에블린!","JPN":"エヴリン！","ENG":"Evelyn!","TWN":"伊芙琳！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"응? 무슨 일이야?","JPN":"あら？　どうしたの？","ENG":"Huh? What is it?","TWN":"嗯？什麼事？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이거 놓고 갔어! <color=#ffd34c>에블린의 연구일지</color>!","JPN":"これ置いて行ったよ！　<color=#ffd34c>エヴリンの研究日誌</color>！","ENG":"You forgot this! <color=#ffd34c>Evelyn’s Research Notes</color>!","TWN":"你忘記帶這個了！<color=#ffd34c>伊芙琳的研究日記</color>！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머. 고마워. 안 그래도 찾고 있었는데.","JPN":"あら。ありがとう。ちょうど探していたところなのよ。","ENG":"Oh, I’ve been looking for that all over. Thanks!","TWN":"哎呀，謝謝。我正在找這個呢。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"하하! 도움이 됐다니 다행이야!","JPN":"ハハ！　お役に立ててよかった！","ENG":"My pleasure!","TWN":"哈哈！幸好有幫上忙！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"혹시…… 내용도 봤니?","JPN":"もしかして……中身も読んだの？","ENG":"Did you read it?","TWN":"不過……你有看裡面的內容嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"내용? 아아. 언뜻 들춰 봤는데 도통 무슨 말인지는 모르겠더라고.","JPN":"内容？　ああ。軽く読んだけど、さっぱりわからないや。","ENG":"Oh, I did, but I didn’t understand a thing.","TWN":"內容？喔喔，是有稍微翻一下，但看不懂在寫什麼。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"대체 <color=#ffd34c>엑자일러</color>가 뭐야? 새로운 마법에 대한 이야긴가?","JPN":"いったい<color=#ffd34c>エグザイラー</color>って何？　新しい魔法についての話？","ENG":"What is an <color=#ffd34c>Exile</color>? Some kind of new magic?","TWN":"到底<color=#ffd34c>流放者</color>是什麼？是新魔法的內容嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"……뭐. 다른 사람도 아니고 우리 가게 마녀니까 괜찮겠지.","JPN":"……まあ、うちのお店の魔女だし大丈夫かな。","ENG":"Well, you’re one of us, so I guess I can tell you.","TWN":"……嗯，反正又不是別人，而是我們店裡的魔女，應該沒關係吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>엑자일러</color>는 본래 이쪽 세계에 속하지 않았던 불청객들을 일컫는 말이야.","JPN":"<color=#ffd34c>エグザイラー</color>は本来この世界に属していなかった、招かれざる客のことよ。","ENG":"We <color=#ffd34c>Exiles</color> are uninvited visitors from another world.","TWN":"<color=#ffd34c>流放者</color>指的是原本不屬於這個世界的不速之客。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"대마녀의 힘 덕에 이곳으로 넘어와 살아가고 있긴 하지만……","JPN":"大魔女の力のおかげでここにわたって来て、生きていけてるけど……","ENG":"We came here thanks to the Great Witch’s power, but...","TWN":"雖然多虧有大魔女的幫助，才能來到這邊生活……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"한때는 우리에게도 집이라고 부를 수 있는 고향이 있었으니까.","JPN":"かつては私たちにも家と呼べる故郷があったの。","ENG":"We used to have a home of our own.","TWN":"但對我們來說，曾經也有能稱之為家的故鄉。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};